class MyThread extends Thread {
  public void run() {
    for (int i = 0; i < 3; i++) {
      System.out.println("Yol işləyir: " + i);
    }
  }
}

public class Main {
  public static void main(String[] args) {
    MyThread thread = new MyThread();
    thread.start();
    System.out.println("Əsas yol işləyir.");
  }
}
// Çıxış (sıra dəyişə bilər):
// Əsas yol işləyir.
// Yol işləyir: 0
// Yol işləyir: 1
// Yol işləyir: 2

class MyRunnable implements Runnable {
  public void run() {
    for (int i = 0; i < 3; i++) {
      System.out.println("Runnable işləyir: " + i);
    }
  }
}

public class Main {
  public static void main(String[] args) {
    Thread thread = new Thread(new MyRunnable());
    thread.start();
    System.out.println("Əsas yol işləyir.");
  }
}
// Çıxış (sıra dəyişə bilər):
